import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F09: 毛利變動與經營槓桿審計 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F09_毛利變動與經營槓桿審計_財務分析專家.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F09_毛利變動與經營槓桿審計_財務分析專家.md"}'),i={name:"審計報告庫/財務審計/3189_景碩/20260423/F09_毛利變動與經營槓桿審計_財務分析專家.md"};function r(d,t,s,o,c,g){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="f09-毛利變動與經營槓桿審計-finance-financial-analyst-審計報告" tabindex="-1">F09: 毛利變動與經營槓桿審計 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f09-毛利變動與經營槓桿審計-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F09: 毛利變動與經營槓桿審計 - finance-financial-analyst 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>毛利率(GM)、營業利益率(OPM)與淨利率的連動關係為何？是否存在經營槓桿(Operating Leverage)放大或侵蝕損益的現象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>截至2025年全年最新公開數據，景碩三率呈現「毛利率下降但營益率與淨利率回升」的結構性偏離：FY2025毛利率21.1%較FY2024的28.4%大幅下滑7.3ppts，但營益率由3.6%升至6.8%(+3.2ppts)，淨利率由4.4%升至6.9%(+2.5ppts)。核心成因是營業費用率從24.9%驟降至14.9%(–10ppts)，暴露企業正經歷「產品組合惡化但費用壓縮救場」的脆弱平衡，評級B(持平)。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B(持平) — 毛利率連續下滑反映ABF載板平均單價(ASP)受壓及原物料成本上漲導致的產品組合劣化，FY2025各季毛利率由Q1的22.5%持續下行至Q3的19.0%後Q4才反彈至22.1%。營益率卻逆勢走升，主因是管銷研三費合計從FY2024的7.59B收縮至FY2025的5.87B(-22.7%)，費用率由24.9%降至14.9%，顯示管理層透過嚴格成本控制抵銷毛利率下滑，但營業費用壓縮至一定程度後將無可再降，屆時若毛利率持續惡化，營益率將面臨急遽下墜風險。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>1. 三率趨勢量化：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">毛利率</th><th style="text-align:center;">營益率</th><th style="text-align:center;">淨利率</th><th style="text-align:center;">營業費用率</th></tr></thead><tbody><tr><td style="text-align:left;">FY2023</td><td style="text-align:center;">27.1%</td><td style="text-align:center;">2.7%</td><td style="text-align:center;">4.7%</td><td style="text-align:center;">24.4%</td></tr><tr><td style="text-align:left;">FY2024</td><td style="text-align:center;">28.4%</td><td style="text-align:center;">3.6%</td><td style="text-align:center;">4.4%</td><td style="text-align:center;">24.9%</td></tr><tr><td style="text-align:left;">FY2025</td><td style="text-align:center;">21.1%</td><td style="text-align:center;">6.8%</td><td style="text-align:center;">6.9%</td><td style="text-align:center;">14.9%</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:center;">22.5%</td><td style="text-align:center;">5.8%</td><td style="text-align:center;">7.1%</td><td style="text-align:center;">16.7%</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:center;">21.1%</td><td style="text-align:center;">6.5%</td><td style="text-align:center;">5.8%</td><td style="text-align:center;">14.6%</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:center;">19.0%</td><td style="text-align:center;">6.1%</td><td style="text-align:center;">5.9%</td><td style="text-align:center;">12.9%</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:center;">22.1%</td><td style="text-align:center;">8.5%</td><td style="text-align:center;">8.7%</td><td style="text-align:center;">13.6%</td></tr></tbody></table><p><strong>2. 經營槓桿係數(DOL)分析：</strong></p><ul><li>FY2024: 營收30.53B, 營利益1.10B</li><li>FY2025: 營收39.35B(+28.8%), 營利益2.67B(+143%)</li><li>DOL = 營利益變動%/營收變動% = 143%/28.8% = 4.97倍</li><li>此超高槓桿係數主因不是規模經濟，而是費用劇降；若還原FY2024費用率24.9%至FY2025(39.35B*24.9%=9.80B)，則營利將從2.67B反轉為虧損-1.26B，凸顯當前獲利基礎極度脆弱</li></ul><p><strong>3. 費用結構拆解(R&amp;D關鍵視角)：</strong></p><ul><li>FY2024營費: 推銷+管理+研發=7.59B，佔營收24.9%</li><li>FY2025營費: 推銷+管理+研發=5.87B，佔營收14.9%</li><li>對照研發費用: FY2024約2.20B(7.2%) vs FY2025約2.15B(5.5%) — 研發絕對金額並未大幅縮減</li><li>推銷費用大減是營費率下降主因，反映景碩可能減少通路費用或客戶自行取貨(物流成本轉嫁)，屬一次性節省，不具永續性</li></ul><p><strong>4. 折舊攤銷對毛利率影響的深度拆解：</strong> 景碩FY2025折舊費用71.6億，佔營收比例高達18.2%，這在載板產業中處於中高檔水準。更重要的是，折舊費用的年增長率從FY2024的15.1%加速至FY2025的17.9%，增速高於期間營收年增率(28.8%)中的結構性部分。若扣除折舊費用對毛利率的壓縮效應，景碩的「現金毛利率」(Gross Profit + Depreciation / Revenue)約為39.3% — 而非報表上的21.1%。這意味著公司在尚未考慮折舊攤銷的現金層面上，每元營收仍能創造近0.4元的現金利潤，但這筆現金利潤中近半數被已投產的資本支出所吞噬。當2026年繼續執行235億擴產計劃時，折舊費用預計在2027-2028年達峰值(約85-95億/年)，屆時即使營收增長至450億以上，折舊/營收比仍需努力壓低至18%以下才能避免損失進一步惡化。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>從華爾街空頭視角審視，景碩FY2025的營益率奇蹟本質上是「會計騙局式獲利」：</p><p><strong>核心風險推演：</strong></p><ol><li><p>毛利率21.1%為近3年最低水準，且Q3一度跌至19.0%的警戒線。管理層解釋為「原物料成本上漲、產品組合變化」，但其實反映ABF載板供過於求的結構性壓力。</p></li><li><p>若推銷費用已壓縮至極限，FY2026無法再降，則營益率將直接跟隨毛利率變動。假設FY2026毛利率回升至23%(樂觀)，營費率維持15%，營益率約8%—但相比同業欣興(預估14%)仍有顯著差距。</p></li><li><p>技術築牆 vs 補貼換盤：研發費用絕對值2.15B穩定投入，FY2025底無形資產增至175M(+230% YoY)，顯示對C2(玻璃基板)等新技術的布局屬於「技術開道」型。但毛利率下滑速度超過研發產出速度，需警惕「研發成果變現率」不足。</p></li></ol><p><strong>物理對策：</strong></p><ul><li>若連續兩季毛利率&lt;20%且營費率無法再降，判定為產品競爭力衰竭，應立即清倉</li><li>關注2026年Q1毛利率是否站回23%以上，若低於預期，則經營槓桿將反向放大虧損(負向槓桿)</li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>FinMind 數據採集器</code>: <code>finance 3189 2023-04-01 2026-04-23 --df</code> (科目: Revenue, CostOfGoodsSold, GrossProfit, OperatingExpenses, OperatingIncome, IncomeAfterTaxes, PreTaxIncome, EPS)</li><li><code>FinMind 數據採集器</code>: <code>revenue 3189 2023-01-01 2026-04-23 --df</code> (科目: monthly revenue for revenue run-rate cross-check)</li><li>Web: <code>聯合新聞網 2026-03-18</code> (報導: 景碩FY2025毛利率21.1%、EPS 3.51元)</li><li><code>yfinance</code>: <code>yf_info 3189.TW</code> (科目: grossMargins, operatingMargins, profitMargins, revenueGrowth, ebitdaMargins)</li></ul>',23)])])}const h=e(i,[["render",r]]);export{p as __pageData,h as default};
